import{_ as a,c as e,q as r,o as s}from"./chunks/framework.CgQGrdLP.js";const o="/assets/list1.Dil0k__D.jpg",l="/assets/list2.Bgho451Z.jpg",p="/assets/list3.TqeKWqzA.jpg",i="/assets/list4.BNWpK7mA.jpg",n="/assets/list5.BW9n2RhU.jpg",P=JSON.parse('{"title":"PaddlePaddle Hackathon | 飞桨黑客马拉松第九期 · 又双叒叕圆满收官啦！","description":"","frontmatter":{"title":"PaddlePaddle Hackathon | 飞桨黑客马拉松第九期 · 又双叒叕圆满收官啦！","date":"2026-01-12T00:00:00.000Z","author":{"name":"刘卓鑫","github":"mattheliu"},"category":"community-activity"},"headers":[],"relativePath":"posts/hackathon-9th-summary.md","filePath":"posts/hackathon-9th-summary.md"}'),d={name:"posts/hackathon-9th-summary.md"};function h(c,t,u,g,_,b){return s(),e("div",null,[...t[0]||(t[0]=[r('<p>一起走过的，不只是四个月的代码 从盛夏出发，在寒冬定稿，开发者们再次写下飞桨生态的新篇章</p><p>时间过得太快了！感觉 8 月 20 日的启动还在昨天，转眼间日历已经翻过了 12 月 19 日（其实已经新一年的一月份了）。</p><p>2025 年 8 月 20 日，飞桨黑客马拉松第九期正式启动。</p><p>2025 年 12 月 19 日，这场跨越盛夏与寒冬的技术共创之旅，正式画上句号。</p><p>四个月，121 天，数不清的 Issue、PR、Review、调试、推翻重来、再提交——</p><p>但最终留下的，不只是合并进主干的代码，更是一群开发者在飞桨生态中的真实成长轨迹。</p><p>不论你是连续参赛的“老面孔”，</p><p>还是第一次踏进飞桨黑客松的新朋友，</p><p>第九期黑客松，因你们而成立，也因你们而完整。</p><hr><h2 id="_01-这个秋冬-我们更-成熟-了" tabindex="-1">01 - 这个秋冬，我们更“成熟”了 <a class="header-anchor" href="#_01-这个秋冬-我们更-成熟-了" aria-label="Permalink to &quot;01 - 这个秋冬，我们更“成熟”了&quot;">​</a></h2><p>第九期黑客松从 2025 年 8 月 20 日 启程，至 2025 年 12 月 19 日 落幕。</p><p>这次我们没玩虚的，赛题更加贴近 <strong>“实战”</strong>。我们延续了大家最爱的经典配方，并在经典赛道基础上，<strong>重磅推出了全新的“文心大模型案例征集”赛道</strong>，让创意直接落地。</p><p>本期我们欣喜地看到，<strong>更复杂的任务被攻克，更创新的方案被实现，更有趣的应用被创造</strong>。在为期四个月的时间里，共有 <strong>25</strong> 位开发者成功完成了最终验收，他们的贡献深度与项目完成质量再创新高。</p><p>每一位参与者的努力都清晰可见，你们提交的 PR、编写的文档、激烈讨论的评论，共同构成了飞桨生态向前迈进的坚实脚印。致敬所有为开源挥洒热情的 Hacker！</p><hr><h2 id="_02-赛道高光-致敬每一位-填坑-人" tabindex="-1">02 - 赛道高光：致敬每一位“填坑”人 <a class="header-anchor" href="#_02-赛道高光-致敬每一位-填坑-人" aria-label="Permalink to &quot;02 - 赛道高光：致敬每一位“填坑”人&quot;">​</a></h2><p>组委会本期共放出了 <strong>227</strong> 个任务，涵盖了从底层框架优化到上层大模型应用的方方面面。感谢每一位在屏幕前熬夜 Coding 的你，是你们让飞桨生态变得更厚实！</p><h3 id="🧱-个人挑战赛-积少成多的力量" tabindex="-1">🧱 个人挑战赛：积少成多的力量 <a class="header-anchor" href="#🧱-个人挑战赛-积少成多的力量" aria-label="Permalink to &quot;🧱 个人挑战赛：积少成多的力量&quot;">​</a></h3><p>这是最热闹的赛道。我们发布了数十个任务，不再单纯追求数量，而是看重代码的“含金量”。</p><ul><li>战绩：发布 <strong>214</strong> 个任务，最终 <strong>22</strong> 位高手成功拿下 <strong>117</strong> 个挑战。</li><li>亮点：很多任务直接涉及到了飞桨框架 3.x 版本的关键特性。你们提交的每一个 PR，都在为千千万万的 AI 开发者减负。</li></ul><blockquote><p>更多详情请查看任务 issue 📄：个人挑战赛 <a href="https://github.com/PaddlePaddle/Paddle/issues/74773" target="_blank" rel="noreferrer">#74773</a>、个人挑战赛冲刺赛 <a href="https://github.com/PaddlePaddle/Paddle/issues/76333" target="_blank" rel="noreferrer">#76333</a></p></blockquote><h3 id="⛵-护航计划集训营-闭关修炼-出关即大神" tabindex="-1">⛵ 护航计划集训营：闭关修炼，出关即大神 <a class="header-anchor" href="#⛵-护航计划集训营-闭关修炼-出关即大神" aria-label="Permalink to &quot;⛵ 护航计划集训营：闭关修炼，出关即大神&quot;">​</a></h3><p>如果你想体验“半个飞桨员工”的感觉，来这里准没错。</p><ul><li>模式：远程实训 + 导师 1V1 带教。</li><li>成果：从 8 月到 12 月，营员们提交了多份高质量周报。最终 3 位同学顺利答辩结营。</li><li>硬核内容：大家攻克了包括算子切分推导规则切多刀功能适配、动转静性能极致优化等在内的多个难题。</li><li>彩蛋：这不仅是集训，更是面试现场！多位表现亮眼的同学已经拿到了飞桨的实习、校招、社招 Offer，欢迎加入！</li></ul><blockquote><p>集训营开源项目地址：<a href="https://github.com/PFCCLab/Camp" target="_blank" rel="noreferrer">https://github.com/PFCCLab/Camp</a>，所有学习笔记与周报记录均留痕～ 更多详情请查看任务 issue 📄：正式批 <a href="https://github.com/PaddlePaddle/Paddle/issues/74775" target="_blank" rel="noreferrer">#74775</a>、提前批 <a href="https://github.com/PaddlePaddle/Paddle/issues/74285" target="_blank" rel="noreferrer">#74285</a></p></blockquote><h3 id="🚀-fundable-projects-高阶玩家的竞技场" tabindex="-1">🚀 Fundable Projects：高阶玩家的竞技场 <a class="header-anchor" href="#🚀-fundable-projects-高阶玩家的竞技场" aria-label="Permalink to &quot;🚀 Fundable Projects：高阶玩家的竞技场&quot;">​</a></h3><p>这里不讲虚的，只解决最棘手的问题。</p><ul><li>定位：聚焦真实场景中的技术痛点，也是资深开发者的最爱。</li><li>成果：本期发布的 4 个关键技术项目，在社区大佬的攻坚下，已有 3 个项目顺利落地。特别是在科学计算和套件适配方向，你们展现了令人惊叹的架构设计能力。</li></ul><blockquote><p>更多详情请查看任务 issue 📄：<a href="https://github.com/PaddlePaddle/Paddle/issues/74774" target="_blank" rel="noreferrer">#74774</a></p></blockquote><h3 id="✨-文心大模型案例征集-脑洞大开的-新战场" tabindex="-1">✨ 文心大模型案例征集：脑洞大开的“新战场” <a class="header-anchor" href="#✨-文心大模型案例征集-脑洞大开的-新战场" aria-label="Permalink to &quot;✨ 文心大模型案例征集：脑洞大开的“新战场”&quot;">​</a></h3><p>这是本期新增的特别赛道，也是最让人眼前一亮的地方。代码很重要，但怎么用好大模型更重要。</p><ul><li>初衷：我们尝试号召社区围绕 文心大模型（ERNIE） 共建高质量的应用案例及教程。最终有 3 个项目通过审核。</li><li>亮点：在这个赛道里，大家化身“产品经理”和“技术布道师”。你们提交的不仅仅是代码，更是一份份保姆级的教程和充满想象力的 Demo。正是你们的努力，持续降低了新手开发者的上手门槛，让大模型应用开发变得不再高冷。</li></ul><blockquote><p>更多详情请查看任务 issue 📄：<a href="https://github.com/PaddlePaddle/Paddle/issues/74776" target="_blank" rel="noreferrer">#74776</a></p></blockquote><hr><h2 id="_03-飞桨因你而-生长" tabindex="-1">03 - 飞桨因你而“生长” <a class="header-anchor" href="#_03-飞桨因你而-生长" aria-label="Permalink to &quot;03 - 飞桨因你而“生长”&quot;">​</a></h2><p>第九期飞桨黑客马拉松结束了，</p><p>但飞桨生态的演进不会停。你们提交的每一行代码，</p><p>写下的不只是功能，</p><p>更是这个社区的信任、协作与长期主义。感谢每一位参与者，</p><p>感谢你们愿意把时间、能力和热情投入到开源这件“慢而正确”的事情上。飞桨的下一次进化，</p><p>仍然会写着你们的名字。</p><p><strong>最后，想对所有参与者说一句：</strong></p><p>无论你这次是拿到了奖金、赢得了 Offer，还是仅仅混了个脸熟、交了几个朋友，<strong>这 121 天的旅程都值得纪念</strong>。新年快乐，各位 Hacker！</p><p>让我们休整片刻，第十期，春天见！一起“搞点大事情”！👋</p><p><strong>121 天·227 坑·25 位勇士·最终通关名单在此！</strong></p><p><img src="'+o+'" alt="list_1"><img src="'+l+'" alt="list_2"><img src="'+p+'" alt="list_3"><img src="'+i+'" alt="list_4"><img src="'+n+'" alt="list_5"></p><hr><h2 id="_04-飞桨专属身份等你-认证" tabindex="-1">04 - 飞桨专属身份等你”认证“ <a class="header-anchor" href="#_04-飞桨专属身份等你-认证" aria-label="Permalink to &quot;04 - 飞桨专属身份等你”认证“&quot;">​</a></h2><p>在参与飞桨黑客松活动时，部分开发者们向飞桨框架提交 PR（Pull Request）参与开源贡献，成为飞桨框架的贡献者，并且有意愿为飞桨框架做出持续的贡献。他们接受了来自 PFCC 的邀请，正在用自己的方式参与飞桨框架建设，与飞桨共同成长。如果你也热爱开源、如果你有意愿成为飞桨开源社区的 Contributor，就快加入 PFCC 吧！</p><blockquote><p><strong>关于 PFCC</strong></p><p>PFCC 全称 Paddle Framework Contributor Club，意为飞桨框架贡献者俱乐部，是一个有兴趣、正在或者已经为飞桨开源框架做开源贡献的贡献者成立的虚拟组织。在这里，飞桨开源框架的贡献者进行讨论、交流和分享，并为飞桨框架做出持续的贡献。如果你有意愿加入我们，请发邮件到<a href="mailto:ext_paddle_oss@baidu.com" target="_blank" rel="noreferrer">ext_paddle_oss@baidu.com</a>，在邮件中附上自己的 GitHub ID、贡献详情与联系方式，会有工作人员邀请你加入。</p></blockquote><p><strong>加入 PFCC，与我们一起参与到飞桨框架的开发中吧！</strong></p><p>戳这里看飞桨开源社区故事 ➡️ <a href="https://pfcc.blog/" target="_blank" rel="noreferrer">https://pfcc.blog/</a></p>',53)])])}const f=a(d,[["render",h]]);export{P as __pageData,f as default};
